import java.lang.reflect.Method;

public class EventDispatcher {

    private final Object handler;

    public EventDispatcher(Object handler) {
        this.handler = handler;
    }

    // Hot path: invoked once per inbound event, thousands of times per second.
    public void dispatch(String eventName, Object payload) {
        Method method = resolve(handler.getClass(), eventName);
        if (method == null) {
            return;
        }
        try {
            method.invoke(handler, payload);
        } catch (ReflectiveOperationException ex) {
            throw new IllegalStateException("dispatch failed: " + eventName, ex);
        }
    }

    private Method resolve(Class<?> type, String name) {
        for (Class<?> c = type; c != null; c = c.getSuperclass()) {
            try {
                return c.getDeclaredMethod(name, Object.class);
            } catch (NoSuchMethodException ex) {
                // intentional: not declared on this class, climb to the superclass
            }
        }
        return null;
    }
}
